class Solution {
public:
    int longestOnes(vector<int>& nums, int k) {
        int zero = 0;
        int count = 0;
        int max = 0;

        for(int i = 0; i < nums.size(); i++){
            while(zero <= k && nums.size() >= i + count){
                if(nums[i + count] == 0){
                    zero++;
                }
                count++;
            }
            max = std::max(max,count);
            count = 0;
            zero = 0;
        }
        return max -1;
    }
};

class Solution {
public:
    int longestOnes(vector<int>& nums, int k) {
        int zero = 0;
        int count = 0;
        int max = 0;

        for(int i = 0; i < nums.size(); i++){
            while(zero <= k && nums.size() > i + count){
                if(nums[i + count] == 0){
                    zero++;
                }
                if(zero <= k)
                count++;
            }
            max = std::max(max,count);
            count = 0;
            zero = 0;
        }
        return max;
    }
};

class Solution {
public:
    int longestOnes(vector<int>& nums, int k) {
        int n = nums.size();
        queue<int> q;
        int maxlen = 0;
        int zeros = 0;

        for (auto i : nums){
            if(i){
                q.push(i);
            }else{
                q.push(i);
                zeros++;
                while(k < zeros){
                    if(q.front() == 0)
                        zeros--;
                        q.pop();
                }
            }
            maxlen = (maxlen > q.size()) ? maxlen : q.size();

        }
        return (maxlen > q.size()) ? maxlen : q.size();

    }
};
